package com.aadil.jobtracker.security;import com.aadil.jobtracker.UserRepository.UserRepository;import com.aadil.jobtracker.entity.UserEntity;import org.springframework.security.authentication.AuthenticationManager;import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;import org.springframework.security.core.Authentication;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.web.bind.annotation.PostMapping;import org.springframework.web.bind.annotation.RequestBody;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.RestController;@RestController@RequestMapping("/api/auth")public class AuthenticationController {    private final UserRepository userRepository;    private final PasswordEncoder passwordEncoder;    private final JwtUtility jwtUtility;    private final AuthenticationManager authenticationManager;    public AuthenticationController(UserRepository userRepository, PasswordEncoder passwordEncoder, JwtUtility jwtUtility, AuthenticationManager authenticationManager) {        this.userRepository = userRepository;        this.passwordEncoder = passwordEncoder;        this.jwtUtility = jwtUtility;        this.authenticationManager = authenticationManager;    }    @PostMapping("/register")    public String register(@RequestBody UserEntity user){        user.setPassword(passwordEncoder.encode(user.getPassword()));        user.setRoles("USER");        userRepository.save(user);        return "User Registered";    }    @PostMapping("/login")    public String login(@RequestBody UserEntity user){        Authentication authentication=authenticationManager.authenticate(new UsernamePasswordAuthenticationToken(user.getName(),user.getPassword()));        if (authentication.isAuthenticated()){            return jwtUtility.generateTokens(user.getName());        }        else {            throw new RuntimeException("Invalid credentials");        }    }}